    after = json.load(f)

def extract_packages(data):
    result = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            fwname = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (pname, fwname, pkg['id'])
                result[key] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return result

b = extract_packages(baseline)
a = extract_packages(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

